def create_server(
    host: str = "0.0.0.0",
    port: int = 50051,
    max_workers: int = None,
    use_so_reuseport: bool = True,
) -> grpc.Server:
    """Create and configure a high-performance gRPC server."""
    
    if max_workers is None:
        import multiprocessing
        max_workers = max(multiprocessing.cpu_count() * 2, 8)
    
    # Thread pool for handling RPCs
    thread_pool = futures.ThreadPoolExecutor(
        max_workers=max_workers,
        thread_name_prefix="grpc-worker",
    )
    
    # Server options optimized for high throughput and low latency
    server_options = [
        # No message size limits
        ("grpc.max_send_message_length", -1),
        ("grpc.max_receive_message_length", -1),
        
        # HTTP/2 tuning for high throughput
        ("grpc.http2.max_pings_without_data", 0),
        ("grpc.http2.min_time_between_pings_ms", 0),
        ("grpc.http2.min_ping_interval_without_data_ms", 0),
        ("grpc.http2.max_ping_strikes", 0),
        
        # Keep-alive settings for persistent connections
        ("grpc.keepalive_time_ms", 10000),           # Send keepalive every 10s
        ("grpc.keepalive_timeout_ms", 5000),          # Wait 5s for keepalive ack
        ("grpc.keepalive_permit_without_calls", 1),   # Allow keepalive without active RPCs
        
        # Connection settings
        ("grpc.max_connection_idle_ms", 0),           # Never close idle connections
        ("grpc.max_connection_age_ms", 0),            # No max connection age
        ("grpc.max_concurrent_streams", 1000),        # High concurrent streams per connection
        
        # Initial window sizes for flow control - large for throughput
        ("grpc.http2.initial_connection_window_size", 16 * 1024 * 1024),  # 16MB
        ("grpc.http2.initial_stream_window_size", 8 * 1024 * 1024),       # 8MB
        
        # Enable SO_REUSEPORT for multi-process scaling
        ("grpc.so_reuseport", int(use_so_reuseport)),
        
        # Compression support
        ("grpc.default_compression_algorithm", 2),     # GZIP
        ("grpc.default_compression_level", 1),         # Low compression for speed
        
        # Large metadata support
        ("grpc.max_metadata_size", 16 * 1024),        # 16KB metadata
    ]
    
    server = grpc.server(
        thread_pool,
        options=server_options,
        maximum_concurrent_rpcs=None,  # No limit on concurrent RPCs
        compression=grpc.Compression.Gzip,
    )
    
    # Register servicer
    servicer = DataStreamServicer()
    datastream_pb2_grpc.add_DataStreamServiceServicer_to_server(servicer, server)
    
    # Bind to address
    address = f"{host}:{port}"
    server.add_insecure_port(address)
    
    logger.info(f"Server configured: address={address}, workers={max_workers}")
    logger.info(f"Server options: {len(server_options)} options configured")
    
    return server, servicer


def serve():
    """Main entry point to start the gRPC server."""
    host = os.environ.get("GRPC_HOST", "0.0.0.0")
    port = int(os.environ.get("GRPC_PORT", "50051"))
    max_workers = int(os.environ.get("GRPC_MAX_WORKERS", "0")) or None
    
    server, servicer = create_server(
        host=host,
        port=port,
        max_workers=max_workers,
    )
    
    # Graceful shutdown handler
    shutdown_event = False
    
    def handle_signal(signum, frame):
        nonlocal shutdown_event
        if not shutdown_event:
            shutdown_event = True
            logger.info(f"Received signal {signum}, initiating graceful shutdown...")
            stats = servicer.metrics.get_stats()
            logger.info(f"Final metrics: {stats}")
            # Grace period of 30 seconds for in-flight RPCs
            event = server.stop(30)
            event.wait()
            logger.info("Server stopped gracefully")
            sys.exit(0)
    
    signal.signal(signal.SIGINT, handle_signal)
    signal.signal(signal.SIGTERM, handle_signal)
    
    server.start()
    logger.info(f"DataStream gRPC server started on {host}:{port}")
    
    # Periodic stats logging
    try:
        while True:
            time.sleep(30)
            stats = servicer.metrics.get_stats()
            logger.info(
                f"Stats: processed={stats['requests_processed']}, "
                f"errors={stats['errors']}, "
                f"avg_latency={stats['avg_latency_ms']:.3f}ms, "
                f"uptime={stats['uptime_seconds']}s, "
                f"stream_in={stats['stream_messages_in']}, "
                f"stream_out={stats['stream_messages_out']}"
            )
    except KeyboardInterrupt:
        handle_signal(signal.SIGINT, None)


